#define IN_RANGE(x, min, max)   ((x)>= (min) && (x)<= (max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<= (b) ? (a) : (b))

void dynproc_openmp(
                int iteration, 
                int *gpuWall,
                int *gpuSrc,
                int *gpuResults,
                int cols, 
                int rows,
                int startStep,
                int border)
{

	int bx = 0;
	int tx=0;

	int small_block_cols = BLOCK_SIZE-iteration*HALO*2;

	int blkX = small_block_cols*bx-border;
	int blkXmax = blkX+BLOCK_SIZE-1;

	int xidx = blkX+tx;

	int validXmin = (blkX < 0) ? -blkX : 0;
	int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

	int W = tx-1;
	int E = tx+1;

	W = (validXmin > W) ? validXmin : W;
	E = (E > validXmax) ? validXmax : E;

	bool isValid = IN_RANGE(tx, validXmin, validXmax);

	if(IN_RANGE(xidx, 0, cols-1)){
            prev[tx] = gpuSrc[xidx];
	}
	bool computed;
	for (int i=0; iteration > i ; i++){ 
            computed = false;
            if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && \
                  isValid){
                  computed = true;
                  int left = prev[W];
                  int up = prev[tx];
                  int right = prev[E];
                  int shortest = MIN(left, up);
                  shortest = MIN(shortest, right);
                  int index = cols*(startStep+i)+xidx;
                  result[tx] = shortest + gpuWall[index];

            }
            if(iteration-1 == i)
                break;
            if(computed)	 
                prev[tx]= result[tx];
      }

	if (computed){
          gpuResults[xidx]=result[tx];		
      }
}

void dynproc_kernel(
                int iteration, 
                int *gpuWall,
                int *gpuSrc,
                int *gpuResults,
                int cols, 
                int rows,
                int startStep,
                int border)
{
    int small_block_cols = BLOCK_SIZE - iteration * HALO * 2;
    int blockCols = cols / small_block_cols + ((cols % small_block_cols == 0) ? 0 : 1);

    #pragma omp parallel for
    for (int bx = 0; bx < blockCols; bx++) {
        int prev[BLOCK_SIZE];
        int result[BLOCK_SIZE];

        int blkX = small_block_cols * bx - border;
        int blkXmax = blkX + BLOCK_SIZE - 1;

        int validXmin = (blkX < 0) ? -blkX : 0;
        int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            int xidx = blkX + tx;

            int W = tx - 1;
            int E = tx + 1;

            W = (validXmin > W) ? validXmin : W;
            E = (E > validXmax) ? validXmax : E;

            bool isValid = IN_RANGE(tx, validXmin, validXmax);

            if (IN_RANGE(xidx, 0, cols - 1)) {
                prev[tx] = gpuSrc[xidx];
            }
        }

        bool computed[BLOCK_SIZE];
        for (int t = 0; t < BLOCK_SIZE; t++) computed[t] = false;

        for (int i = 0; i < iteration; i++) {
            for (int tx = validXmin; tx <= validXmax; tx++) {
                if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2)) {
                    computed[tx] = true;
                    int W = tx - 1;
                    int E = tx + 1;
                    W = (validXmin > W) ? validXmin : W;
                    E = (E > validXmax) ? validXmax : E;

                    int left = prev[W];
                    int up = prev[tx];
                    int right = prev[E];
                    int shortest = MIN(left, up);
                    shortest = MIN(shortest, right);
                    int xidx = blkX + tx;
                    int index = cols * (startStep + i) + xidx;
                    result[tx] = shortest + gpuWall[index];
                }
            }

            if (iteration - 1 == i)
                break;

            for (int tx = validXmin; tx <= validXmax; tx++) {
                if (computed[tx])
                    prev[tx] = result[tx];
            }
        }

        for (int tx = validXmin; tx <= validXmax; tx++) {
            if (computed[tx]) {
                int xidx = blkX + tx;
                if (IN_RANGE(xidx, 0, cols - 1)) {
                    gpuResults[xidx] = result[tx];
                }
            }
        }
    }
}

int calc_path(int *gpuWall, int *gpuResult[2], int rows, int cols, \
	 int pyramid_height, int blockCols, int borderCols)
{
	int src = 1, dst = 0;
	for (int t = 0; rows-1 > t; t+=pyramid_height) {
            int temp = src;
            src = dst;
            dst = temp;
            dynproc_kernel(
                MIN(pyramid_height, rows-t-1), 
                gpuWall, gpuResult[src], gpuResult[dst],
                cols,rows, t, borderCols);
	}
        return dst;
}

int main(int argc, char** argv)
{
    run(argc,argv);

    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);


    int borderCols = (pyramid_height)*HALO;
    int smallBlockCol = BLOCK_SIZE-(pyramid_height)*HALO*2;
    int blockCols = cols/smallBlockCol+((0 == cols%smallBlockCol)?0:1);

    printf("pyramidHeight: %d\ngridSize: [%d]\nborder:[%d]\nblockSize: %d\nblockGrid:[%d]\ntargetBlock:[%d]\n",\
	pyramid_height, cols, borderCols, BLOCK_SIZE, blockCols, smallBlockCol);

    int *gpuWall, *gpuResult[2];
    int size = rows*cols;

    gpuResult[0] = new int[cols];
    gpuResult[1] = new int[cols];
    memcpy(gpuResult[0], data, sizeof(int)*cols);
    gpuWall = new int[size-cols];
    memcpy(gpuWall, data+cols, sizeof(int)*(size-cols));

#ifdef  TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    int final_ret = calc_path(gpuWall, gpuResult, rows, cols, \
	 pyramid_height, blockCols, borderCols);

#ifdef  TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    memcpy(result, gpuResult[final_ret], sizeof(int)*cols);

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
            printf("%d ",data[i]) ;
    printf("\n") ;
    for (int i = 0; i < cols; i++)
            printf("%d ",result[i]) ;
    printf("\n") ;
#endif

    delete [] gpuWall;
    delete [] gpuResult[0];
    delete [] gpuResult[1];

    delete [] data;
    delete [] wall;
    delete [] result;

#ifdef  TIMING
    printf("Exec: %f\n", kernel_time);
#endif
}
